Here's a complete implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}" FontSize="12"
                               TextColor="{StaticResource Gray500}" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to dismiss spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.NavigateToDetailAsync(SelectedItem);
        SelectedItem = null; // Reset so same item can be re-selected
    }
}
```

### Key bindings explained

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool) | Controls the refresh spinner; **must set `false`** when done |
| `Command` (RefreshView) | `RefreshCommand` | Fires on pull-down; calls your API |
| `ItemsSource` | `Items` (ObservableCollection) | Use `ObservableCollection<T>` so add/remove updates the UI |
| `SelectedItem` | `SelectedItem` (TwoWay) | Holds the tapped item; reset to `null` after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap; triggers navigation |

### Important notes

- **Always use `ObservableCollection<T>`**, not `List<T>` — swapping a `List` forces a full re-render.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always dismisses.
- **Reset `SelectedItem = null`** after navigating so the user can tap the same item again.
- **Set `x:DataType`** on the `DataTemplate` for compiled bindings and better performance.
- **Never use `ViewCell`** — use `Grid`, `StackLayout`, or any `View` as the template root.
